using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
}

public class Event
{
    public int Id { get; set; }
    public int TotalSeats { get; set; }
    public int AvailableSeats { get; set; }
}

public class TicketService
{
    private readonly EventBookingContext _context;

    public TicketService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        var @event = await _context.Events.FindAsync(eventId);

        if (@event == null || quantity <= 0)
        {
            return false;
        }

        if (quantity > @event.AvailableSeats)
        {
            return false;
        }

        // Use optimistic concurrency control
        int originalAvailableSeats = @event.AvailableSeats;
        @event.AvailableSeats -= quantity;

        try
        {
            _context.Entry(@event).Property(e => e.AvailableSeats).OriginalValue = originalAvailableSeats;
            await _context.SaveChangesAsync();
            return true;
        }
        catch (DbUpdateConcurrencyException)
        {
            // Handle concurrency conflict, e.g., retry or notify user
            return false;
        }
    }
}